function run(label,fn,...args){
  try{
    const result=fn(...args);
    if(result&&typeof result.then==='function') result.catch(err=>handleError(label,err));
    return result;
  }catch(err){handleError(label,err);}
}
function handleError(label,err){
  console.error(`[Valora Pulse] ${label}`,err);
  toast(`Não foi possível concluir ${label}. ${err?.message||err}`,'error');
  try{audit('Erro tratado','sistema','',`${label}: ${err?.message||err}`);}catch(_){ }
}

window.addEventListener('error',e=>handleError('a operação',e.error||new Error(e.message)));
window.addEventListener('unhandledrejection',e=>handleError('a operação assíncrona',e.reason||new Error('Falha desconhecida')));
document.addEventListener('DOMContentLoaded',()=>run('a inicialização',init));
document.addEventListener('click',e=>{
  const el=e.target.closest('[data-action]'); if(!el)return;
  const action=actions[el.dataset.action]; if(!action)return;
  e.preventDefault(); run(`a ação “${el.dataset.action}”`,action,el,e);
});
document.addEventListener('change',e=>{
  const el=e.target.closest('[data-change]');if(!el)return;
  const change=changes[el.dataset.change];if(change)run(`a alteração “${el.dataset.change}”`,change,el,e);
});
document.addEventListener('input',e=>{
  const el=e.target.closest('[data-input]');if(!el)return;
  const change=inputs[el.dataset.input];if(change)run(`a edição “${el.dataset.input}”`,change,el,e);
});
document.addEventListener('submit',e=>{
  const form=e.target.closest('form[data-form]');if(!form)return;
  e.preventDefault();const handler=formHandlers[form.dataset.form];if(handler)run(`o envio de “${form.dataset.form}”`,handler,form,e);
});
document.addEventListener('keydown',e=>{
  if(e.key==='Escape'){
    if($('#confirmLayer')?.classList.contains('open'))closeConfirm();
    else if($('#modalLayer')?.classList.contains('open'))closeModal();
    else toggleBot(false);
  }
});

async function init(){
  if(!repository)throw new Error('Camada de repositório não carregada.');
  if(repository.mode==='firebase'&&window.ValoraFirebaseAuth?.waitUntilReady)await window.ValoraFirebaseAuth.waitUntilReady();
  window.addEventListener('valora:auth-changed',()=>routeFromLocation());
  renderShell();
  routeFromLocation();
  window.addEventListener('hashchange',routeFromLocation);
  window.addEventListener('popstate',routeFromLocation);
  updateEmailStatus();
}
function routeFromLocation(){
  const u=new URL(location.href);const hash=(location.hash||'').slice(1);const sid=u.searchParams.get('survey'),token=u.searchParams.get('token'),result=u.searchParams.get('result'),resultToken=u.searchParams.get('rt');
  // Rotas internas sempre têm prioridade. Assim, Minha área, logo, LGPD e Planos
  // continuam funcionando mesmo depois de abrir um link seguro com query string.
  if(hash)return route(hash);
  if(sid&&token)return renderTakeSurvey(sid,token);
  if(result)return renderResult(result,false,resultToken);
  route('home');
}
function route(path){
  currentRoute=path||'home';renderShell();
  const [view,tab]=currentRoute.split('/');
  if(['admin','empresa','participante'].includes(view)&&!currentUser())return renderLogin('Entre para acessar sua área.');
  if(view==='admin'&&!['admin_valora','consultor_valora'].includes(currentUser()?.role))return renderNoAccess();
  if(view==='empresa'&&!['empresa_admin','gestor_pesquisa','admin_valora','consultor_valora'].includes(currentUser()?.role))return renderNoAccess();
  if(view==='participante'&&currentUser()?.role!=='participante')return renderNoAccess();
  const views={home:renderHome,login:renderLogin,signup:renderSignup,lgpd:renderPublicLgpd,plans:renderPlans,admin:()=>renderPortal('admin',tab||'dashboard'),empresa:()=>renderPortal('empresa',tab||'dashboard'),participante:()=>renderPortal('participante',tab||'dashboard')};
  (views[view]||renderHome)();setTimeout(()=>{const app=$('#app');if(app){try{app.focus({preventScroll:true});}catch(_){app.focus();window.scrollTo({top:0,behavior:'auto'});}}},0);
}
function navigate(path){document.body.classList.remove('menu-open');$('#navActions')?.classList.remove('open');const menuBtn=$('.mobile-menu');if(menuBtn)menuBtn.setAttribute('aria-expanded','false');const clean=location.href.split('?')[0].split('#')[0];history.pushState({},'',`${clean}#${path}`);route(path);window.scrollTo({top:0,behavior:'auto'});}
function goHome(){
  const clean=location.href.split('?')[0].split('#')[0];history.replaceState({},'',`${clean}#home`);route('home');window.scrollTo({top:0,behavior:'smooth'});
}

